namespace sv_9d1a44ee8d0246f785938d3b2e8603eb.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public record ShipmentDetails(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> Updates);

public record StatusUpdate(string Description, DateTimeOffset Timestamp);

using sv_9d1a44ee8d0246f785938d3b2e8603eb.Client.Services;

namespace sv_9d1a44ee8d0246f785938d3b2e8603eb.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new ShipmentDetails(
            "PKG-001",
            "In Transit",
            "Chicago, IL",
            DateTimeOffset.UtcNow.AddDays(2),
            [
                new StatusUpdate("Package picked up", DateTimeOffset.UtcNow.AddDays(-3)),
                new StatusUpdate("Arrived at sorting facility", DateTimeOffset.UtcNow.AddDays(-2)),
                new StatusUpdate("In transit to destination", DateTimeOffset.UtcNow.AddDays(-1)),
            ]),
        ["PKG-002"] = new ShipmentDetails(
            "PKG-002",
            "Delivered",
            "Austin, TX",
            DateTimeOffset.UtcNow.AddDays(-1),
            [
                new StatusUpdate("Package picked up", DateTimeOffset.UtcNow.AddDays(-5)),
                new StatusUpdate("Arrived at regional hub", DateTimeOffset.UtcNow.AddDays(-4)),
                new StatusUpdate("Out for delivery", DateTimeOffset.UtcNow.AddDays(-1)),
                new StatusUpdate("Delivered", DateTimeOffset.UtcNow.AddDays(-1).AddHours(3)),
            ]),
        ["PKG-003"] = new ShipmentDetails(
            "PKG-003",
            "Processing",
            "Seattle, WA",
            DateTimeOffset.UtcNow.AddDays(5),
            [
                new StatusUpdate("Label created", DateTimeOffset.UtcNow.AddHours(-6)),
                new StatusUpdate("Awaiting carrier pickup", DateTimeOffset.UtcNow.AddHours(-2)),
            ]),
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_9d1a44ee8d0246f785938d3b2e8603eb.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<Shipment> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <h2>Shipment @_shipment.TrackingNumber</h2>
    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>
        <dt>Location</dt>
        <dd>@_shipment.Location</dd>
        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h3>Status Updates</h3>
    <ul>
        @foreach (var update in _shipment.Updates)
        {
            <li>@update.Timestamp.ToString("g") &mdash; @update.Description</li>
        }
    </ul>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _shipment = null;
        _errorMessage = null;
        _loading = true;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed; do nothing
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RetryLoad()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

