using System.Net;
using System.Net.Http.Json;

namespace sv_9d1a44ee8d0246f785938d3b2e8603eb.Client.Services;

/// <summary>
/// Client-side implementation that calls the server API over HTTP.
/// Used when running on WebAssembly.
/// </summary>
public class ShipmentServiceClient : IShipmentService
{
    private readonly HttpClient _http;

    public ShipmentServiceClient(HttpClient http)
    {
        _http = http;
    }

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await _http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == HttpStatusCode.NotFound)
        {
            throw new KeyNotFoundException($"Shipment '{trackingNumber}' was not found.");
        }

        response.EnsureSuccessStatusCode();

        return await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct)
            ?? throw new InvalidOperationException("Received null shipment data.");
    }
}

